/**
 * mcp-readiness.ts — External MCP readiness probe (ASL-0011)
 *
 * Discovers and probes external plugin-installed MCP servers for the current
 * project. Process-existence check only — no JSON-RPC ping. Mirrors the
 * structural idiom of checkJudgeHealth (Promise.allSettled + classify + envelope)
 * without importing judge-panel.ts.
 *
 * Hard rules:
 *   - Never throws. All errors become ok:false or return empty defaults.
 *   - Never spawns or restarts any MCP server. Read-only probe.
 *   - Never blocks session start. 1500ms hard wall-clock ceiling.
 *   - Local freddie-ai MCP is always excluded.
 */

import { readFileSync } from "fs";
import { join } from "path";
import os from "os";
import { execFile, execFileSync, execSync } from "child_process";
import { fromRoot } from "./paths.js";

// ── Types ─────────────────────────────────────────────────────────────────

/**
 * Error types for MCP readiness failures.
 * - "no-process": plugin installed but no matching process found
 * - "config-error": .mcp.json malformed or missing server entries
 * - "api": probe threw, timed out, or encountered an unexpected error
 *
 * Note: "not-installed" and "stale-pid" were originally in the union but
 * are unreachable in the current process-existence-only probe strategy.
 * They have been removed to avoid dead union members. Add them back if a
 * real PID-file probe path is implemented.
 */
export type McpReadinessErrorType = "no-process" | "config-error" | "api";

export interface McpReadinessEntry {
  name: string;            // MCP server name (e.g. "discord", "mcp-search")
  plugin: string;          // plugin id (e.g. "discord@claude-plugins-official")
  ok: boolean;
  reason?: string;         // human-readable failure reason when !ok
  errorType?: McpReadinessErrorType;
  remediation?: string;    // one-liner the user can act on
}

export interface McpReadinessResult {
  enabled: boolean;        // mirrors settings flag
  ready: McpReadinessEntry[];
  notReady: McpReadinessEntry[];
  ignored: string[];       // server names skipped due to ignore list

