 * returns empty — the caller receives [] and marks all probes as no-process.
 * A stderr line is emitted so the user has a debuggable signal.
 *
 * Exported for test use. Sync variant used by the async wrapper below.
 */
export function _enumerateBunProcesses(): ProcessEntry[] {
  const isWindows = process.platform === "win32";

  if (isWindows) {
    // PowerShell Get-CimInstance: filters bun.exe and node.exe, outputs quoted CSV.
    // Handles embedded commas in CommandLine correctly.
    // Uses execFileSync (not execSync) to bypass cmd.exe shell — avoids quoting
    // issues where cmd.exe splits the PowerShell pipeline on the | character.
    let psOut: string;
    try {
      psOut = execFileSync(
        "powershell",
        [
          "-NoProfile",
          "-Command",
          "Get-CimInstance Win32_Process -Filter \"Name='bun.exe' OR Name='node.exe'\" | Select-Object ProcessId,CommandLine | ConvertTo-Csv -NoTypeInformation",
        ],
        { timeout: 3000, encoding: "utf-8" }
