    } catch (err) {
      // PowerShell failed — extremely unlikely but log so the user can diagnose
      const msg = err instanceof Error ? err.message : String(err);
      process.stderr.write(`[mcp-readiness] PowerShell process enumeration failed: ${msg}\n`);
      return [];
    }

    return parsePowerShellCsv(psOut);
  } else {
    // Unix: ps -eo pid,command
    let psOut: string;
    try {
      psOut = execSync("ps -eo pid,command", {
        timeout: 2000,
        encoding: "utf-8",
        stdio: ["pipe", "pipe", "pipe"],
      });
    } catch (err) {
      const msg = err instanceof Error ? err.message : String(err);
      process.stderr.write(`[mcp-readiness] ps enumeration failed: ${msg}\n`);
      return [];
    }

    return parsePsOutput(psOut);
  }
