 * On Unix, wraps ps in a Promise. Never throws — logs and returns [] on error.
 */
async function _enumerateBunProcessesAsync(): Promise<ProcessEntry[]> {
  const isWindows = process.platform === "win32";

  if (isWindows) {
    return new Promise<ProcessEntry[]>((resolve) => {
      execFile(
        "powershell",
        [
          "-NoProfile",
          "-Command",
          "Get-CimInstance Win32_Process -Filter \"Name='bun.exe' OR Name='node.exe'\" | Select-Object ProcessId,CommandLine | ConvertTo-Csv -NoTypeInformation",
        ],
        { timeout: 3000, encoding: "utf-8" },
        (err, stdout) => {
          if (err) {
            const msg = err instanceof Error ? err.message : String(err);
            process.stderr.write(`[mcp-readiness] PowerShell process enumeration failed: ${msg}\n`);
            resolve([]);
            return;
          }
          resolve(parsePowerShellCsv(stdout as string));
        }
      );
    });
  } else {
    return new Promise<ProcessEntry[]>((resolve) => {
      execFile(
        "ps",
        ["-eo", "pid,command"],
        { timeout: 2000, encoding: "utf-8" },
        (err, stdout) => {
          if (err) {
            const msg = err instanceof Error ? err.message : String(err);
            process.stderr.write(`[mcp-readiness] ps enumeration failed: ${msg}\n`);
            resolve([]);
            return;
          }
          resolve(parsePsOutput(stdout as string));
        }
      );
    });
  }
}

