/**
 * platform.ts — OS and shell detection utilities
 *
 * Detects the runtime platform, architecture, and active shell environment.
 * Used by other tools to make cross-platform decisions.
 */

import { existsSync } from "fs";
import { join } from "path";

export type Platform = "win32" | "darwin" | "linux" | "unknown";
export type Shell = "bash" | "zsh" | "fish" | "nushell" | "powershell" | "cmd" | "unknown";

export interface PlatformInfo {
  os: Platform;
  arch: string;
  shell: Shell;
  home: string;
  pathSep: string;       // PATH delimiter (":" or ";")
  exeExt: string[];      // executable extensions to try
}

/** Detect the current platform, shell, and relevant paths. */
export function detectPlatform(): PlatformInfo {
  const os = detectOS();
  return {
    os,
    arch: process.arch,
    shell: detectShell(),
    home: process.env.HOME || process.env.USERPROFILE || "",
    pathSep: os === "win32" ? ";" : ":",
    exeExt: os === "win32" ? [".cmd", ".bat", ".exe", ".ps1", ""] : [""],
  };
}

function detectOS(): Platform {
  switch (process.platform) {
    case "win32": return "win32";
    case "darwin": return "darwin";
    case "linux": return "linux";
    default: return "unknown";
  }
}

function detectShell(): Shell {
  // Check SHELL env (Unix)
  const shellEnv = process.env.SHELL || "";
  if (shellEnv.includes("zsh")) return "zsh";
  if (shellEnv.includes("bash")) return "bash";
  if (shellEnv.includes("fish")) return "fish";
  if (shellEnv.includes("nu")) return "nushell";

  // Check NU_VERSION (nushell sets this)
  if (process.env.NU_VERSION) return "nushell";

  // Check PSModulePath (PowerShell sets this)
  if (process.env.PSModulePath) return "powershell";

  // Check ComSpec (Windows cmd)
  if (process.env.ComSpec?.toLowerCase().includes("cmd.exe")) return "cmd";

  // Check TERM_PROGRAM for macOS terminals
  if (process.env.TERM_PROGRAM === "iTerm.app" || process.env.TERM_PROGRAM === "Apple_Terminal") {
    return shellEnv ? detectShellFromPath(shellEnv) : "zsh"; // macOS defaults to zsh
  }

  return "unknown";
}

function detectShellFromPath(shellPath: string): Shell {
  const name = shellPath.split("/").pop() || "";
  if (name === "zsh") return "zsh";
  if (name === "bash") return "bash";
  if (name === "fish") return "fish";
  if (name === "nu") return "nushell";
  return "unknown";
}

